def orangesRotting(grid):
    r, c = len(grid), len(grid[0])
    q = collections.deque([(i, j, 0) for i in range(r) for j in range(c) if grid[i][j] == 2])
    fresh = sum(grid[i][j] == 1 for i in range(r) for j in range(c))
    time = 0
    while q:
        i, j, d = q.popleft(); time = max(time, d)
        for ni, nj in [(i-1,j),(i+1,j),(i,j-1),(i,j+1)]:
            if 0<=ni<r and 0<=nj<c and grid[ni][nj] == 1:
                grid[ni][nj] = 2; fresh -= 1; q.append((ni, nj, d+1))
    return time if fresh == 0 else -1

